#include <stdio.h>
#include <string.h>

// ★ Stage 0 — Exemple complet
int main(void) {
    const char *status =
        "Name:\tkernelforge\n"
        "Pid:\t42\n"
        "PPid:\t1\n"
        "State:\tS (sleeping)\n"
        "VmRSS:\t4096 kB\n"
        "Threads:\t3\n";
    FILE *f = fmemopen((void *)status, strlen(status), "r"); // ★ simuler /proc/42/status
    if (!f) return 1;
    char line[128], key[64], val[64];
    while (fgets(line, sizeof(line), f)) {
        line[strcspn(line, "\n")] = 0;
        // ★ %63[^:] = tout sauf ':', :\t = séparer clé:val, %63[^\n] = valeur
        if (sscanf(line, "%63[^:]:\t%63[^\n]", key, val) == 2) {
            if (!strcmp(key, "Name") || !strcmp(key, "Pid") ||
                !strcmp(key, "State") || !strcmp(key, "VmRSS")) {
                printf("%s = %s\n", key, val); // ★ filtre les 4 champs voulus
            }
        }
    }
    fclose(f);
    return 0;
}

